def family(fid: str, name: str, manufacturer: str, qualification: str, mechanic: str, standardization: str, tags: list[str], notes: str) -> dict[str, object]:
    return {
        "family_id": fid,
        "display_name": name,
        "manufacturer": manufacturer,
        "qualification_group": qualification,
        "mechanic_group": mechanic,
        "standardization_group": standardization,
        "family_role_tags": tags,
        "notes": notes,
    }


def msfs_meta(status: str, available: bool, note: str, example_products: list[str], source_refs: list[str], *, included_tier: str = "", distribution_channels: list[str] | None = None) -> dict[str, object]:
    return {
        "msfs2024_available_for_user": available,
        "msfs2024_status": status,
        "msfs2024_included_tier": included_tier,
        "msfs2024_distribution_channels": distribution_channels or [],
        "msfs2024_example_products": example_products,
        "msfs2024_source_refs": source_refs,
        "msfs2024_user_note": note,
        "msfs2024_last_verified_on": LAST_VERIFIED_ON,
    }


def available_manuals(products: list[str], note: str | None = None, *, included_tier: str = "included", channels: list[str] | None = None) -> dict[str, object]:
    return msfs_meta(
        "confirmed_available",
        True,
        note or "Confirmed as a current MSFS 2024 aircraft on the official aircraft manuals page.",
        products,
        [SOURCE_REFS["msfs2024_manuals"]],
        included_tier=included_tier,
        distribution_channels=channels or ["included_first_party"],
    )


def available_release(products: list[str], refs: list[str], note: str | None = None, *, included_tier: str = "included", channels: list[str] | None = None) -> dict[str, object]:
    return msfs_meta(
        "confirmed_available",
        True,
        note or "Confirmed as a current MSFS 2024 aircraft in official release notes.",
        products,
        refs,
        included_tier=included_tier,
        distribution_channels=channels or ["included_first_party"],
    )


def available_vendor(products: list[str], refs: list[str], note: str, *, included_tier: str = "", channels: list[str] | None = None) -> dict[str, object]:
    return msfs_meta(
        "confirmed_available",
        True,
        note,
        products,
        refs,
        included_tier=included_tier,
        distribution_channels=channels or ["third_party_paid"],
    )


def unavailable_vendor(products: list[str], refs: list[str], note: str, *, channels: list[str] | None = None) -> dict[str, object]:
    return msfs_meta(
        "confirmed_unavailable",
        False,
        note,
        products,
        refs,
        distribution_channels=channels or ["third_party_paid"],
    )


def not_verified(note: str = DEFAULT_NOT_VERIFIED_NOTE) -> dict[str, object]:
    return msfs_meta("not_verified", False, note, [], [])


def model(
    base: dict[str, object],
    meta: dict[str, object],
    model_id: str,
    family_id: str,
    display_name: str,
    short_name: str,
    variant_kind: str,
    in_service_role: str,
    max_passengers: int,
    max_cargo_lb: int,
    market_role_pool: str,
    best_fit_contract_tags: list[str],
    notes: str,
    **overrides: object,
) -> dict[str, object]:
    return base | meta | {
        "model_id": model_id,
        "family_id": family_id,
        "display_name": display_name,
        "short_name": short_name,
        "variant_kind": variant_kind,
        "in_service_role": in_service_role,
        "max_passengers": max_passengers,
        "max_cargo_lb": max_cargo_lb,
        "market_role_pool": market_role_pool,
        "best_fit_contract_tags": best_fit_contract_tags,
        "notes": notes,
    } | overrides


def cargo_capacity_for_layout(model: dict[str, object], total_seats: int, factor: float) -> int:
    max_cargo = int(model["max_cargo_lb"])
    if int(model["max_passengers"]) <= 0:
        return max_cargo
    seat_ratio = max(0.0, min(1.0, total_seats / int(model["max_passengers"])))
    modifier = 1.10 - (seat_ratio * 0.20)
    return min(max_cargo, int(round(max_cargo * modifier * factor)))


def make_layout(model: dict[str, object], suffix: str, display_name: str, config_type: str, *, total: int, first: int = 0, business: int = 0, premium: int = 0, economy: int = 0, cargo_factor: float = 1.0, is_default: bool = False, notes: str = "") -> dict[str, object]:
    return {
        "layout_id": f"{model['model_id']}__{suffix}",
        "model_id": model["model_id"],
        "display_name": display_name,
        "config_type": config_type,
        "is_default": is_default,
        "total_seats": total,
        "first_class_seats": first,
        "business_class_seats": business,
        "premium_economy_seats": premium,
        "economy_seats": economy,
        "cargo_capacity_lb": cargo_capacity_for_layout(model, total, cargo_factor),
        "notes": notes,
    }


