def build_cabin_layouts(models: list[dict[str, object]]) -> list[dict[str, object]]:
    layouts: list[dict[str, object]] = []
    for model_item in models:
        max_pax = int(model_item["max_passengers"])
        style = str(model_item.get("layout_style", ""))
        if max_pax <= 0 or style == "cargo":
            continue
        if style == "executive":
            layouts.append(make_layout(model_item, "executive", "Executive Layout", "executive", total=max_pax, business=max_pax, cargo_factor=0.95, is_default=True, notes="Single-cabin premium executive layout."))
            continue
        if style == "utility":
            layouts.append(make_layout(model_item, "utility_standard", "Utility Standard", "single_class", total=max_pax, economy=max_pax, cargo_factor=0.88, is_default=True, notes="Simple all-economy or bench-seating utility layout."))
            combi_total = max(6, int(round(max_pax * 0.7)))
            layouts.append(make_layout(model_item, "utility_flex", "Utility Flex", "combi", total=combi_total, economy=combi_total, cargo_factor=1.0, notes="Reduced seating to preserve more mixed payload capability."))
            continue
        if style == "commuter":
            layouts.append(make_layout(model_item, "single_class", "Single Class", "single_class", total=max_pax, economy=max_pax, cargo_factor=0.86, is_default=True, notes="Highest seat-count commuter layout."))
            premium_total = max(max_pax - 2, int(round(max_pax * 0.9)))
            business = min(6, max(2, int(round(premium_total * 0.12))))
            economy = premium_total - business
            layouts.append(make_layout(model_item, "regional_plus", "Regional Plus", "two_class", total=premium_total, business=business, economy=economy, cargo_factor=0.95, notes="Adds a small premium section for higher-yield regional contracts."))
            continue
        if style == "regional":
            layouts.append(make_layout(model_item, "single_class", "Single Class", "single_class", total=max_pax, economy=max_pax, cargo_factor=0.85, is_default=True, notes="Highest seat-count regional layout."))
            two_class_total = max(max_pax - 6, int(round(max_pax * 0.9)))
            business = max(6, int(round(two_class_total * 0.12)))
            economy = two_class_total - business
            layouts.append(make_layout(model_item, "two_class", "Two Class", "two_class", total=two_class_total, business=business, economy=economy, cargo_factor=0.95, notes="Adds a business section for higher-yield scheduled flying."))
            if bool(model_item.get("combi_capable", False)):
                combi_total = max(18, int(round(max_pax * 0.65)))
                layouts.append(make_layout(model_item, "cargo_flex", "Cargo Flex", "combi", total=combi_total, economy=combi_total, cargo_factor=1.0, notes="Reduced seat count to preserve more mixed passenger and freight capacity."))
            continue
        if style == "regional_jet":
            layouts.append(make_layout(model_item, "single_class", "Single Class", "single_class", total=max_pax, economy=max_pax, cargo_factor=0.84, is_default=True, notes="Highest seat-count regional jet layout."))
            two_class_total = max(max_pax - 8, int(round(max_pax * 0.9)))
            business = max(8, int(round(two_class_total * 0.14)))
            economy = two_class_total - business
            layouts.append(make_layout(model_item, "two_class", "Two Class", "two_class", total=two_class_total, business=business, economy=economy, cargo_factor=0.94, notes="Adds a business cabin for premium regional service."))
            continue
        if style == "narrowbody":
            layouts.append(make_layout(model_item, "high_density", "High Density", "single_class", total=max_pax, economy=max_pax, cargo_factor=0.82, is_default=True, notes="Highest seat-count narrowbody layout."))
            two_class_total = max(max_pax - 18, int(round(max_pax * 0.9)))
            business = max(12, int(round(two_class_total * 0.12)))
            economy = two_class_total - business
            layouts.append(make_layout(model_item, "two_class", "Two Class", "two_class", total=two_class_total, business=business, economy=economy, cargo_factor=0.92, notes="Standard business-plus-economy network layout."))
            premium_total = max(max_pax - 34, int(round(max_pax * 0.82)))
            first = 8 if max_pax >= 180 else 0
            business = 24 if max_pax >= 180 else 16
            premium = 12 if max_pax >= 180 else 0
            economy = max(0, premium_total - first - business - premium)
            layouts.append(make_layout(model_item, "premium", "Premium", "premium", total=premium_total, first=first, business=business, premium=premium, economy=economy, cargo_factor=1.0, notes="Higher-yield narrowbody configuration with more premium seating."))
            continue
        if style == "widebody":
            layouts.append(make_layout(model_item, "leisure", "Leisure Dense", "single_class", total=max_pax, economy=max_pax, cargo_factor=0.80, is_default=True, notes="Highest seat-count long-haul leisure layout."))
            two_class_total = max(max_pax - 30, int(round(max_pax * 0.88)))
            business = max(28, int(round(two_class_total * 0.12)))
            economy = max(0, two_class_total - business)
            layouts.append(make_layout(model_item, "two_class", "Two Class", "two_class", total=two_class_total, business=business, economy=economy, cargo_factor=0.92, notes="Business-plus-economy network widebody layout."))
            premium_total = max(max_pax - 70, int(round(max_pax * 0.78)))
            first = 10 if max_pax >= 320 else 8
            business = max(32, int(round(premium_total * 0.14)))
            premium = max(18, int(round(premium_total * 0.08)))
            economy = max(0, premium_total - first - business - premium)
            layouts.append(make_layout(model_item, "longhaul_premium", "Long-Haul Premium", "premium", total=premium_total, first=first, business=business, premium=premium, economy=economy, cargo_factor=1.0, notes="Higher-yield intercontinental configuration with first, business, and premium economy seats."))
            continue
    return layouts


